const item = $input.item;
const j = item.json;

const fileId = j.id || '';
if (!fileId) {
    throw new Error('file_id não encontrado. Campos: ' + JSON.stringify(Object.keys(j)));
}

item.json.claude_body = JSON.stringify({
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 8096,
    messages: [{
        role: 'user',
        content: [
            {
                type: 'document',
                source: {
                    type: 'file',
                    file_id: fileId
                }
            },
            {
                type: 'text',
                text: `Você é especialista em MDM (Master Data Management), classificações fiscais brasileiras e plano de contas contábil (NBC TG).

Analise esta proposta comercial e extraia TODOS os itens/produtos/serviços listados.

Para cada item retorne os campos abaixo. Use seu conhecimento técnico para preencher os campos de classificação quando não estiverem explícitos na proposta.

CAMPOS OBRIGATÓRIOS:
- codigo: código do produto conforme proposta (string)
- nome: nome comercial completo (string, máx 120 chars)
- descricao_curta: resumo técnico em até 80 caracteres (string)
- descricao_longa: especificação técnica detalhada (string)
- unidade: unidade de medida (UN, KG, M, L, CX, KWP, etc.)
- categoria: categoria do produto (ex: Energia Solar, Cabos e Conectores, Estrutura, Serviços, etc.)
- preco_unitario: valor unitário como número sem símbolo de moeda (ex: 1250.00)
- fabricante: nome do fabricante ou fornecedor conforme proposta

CLASSIFICAÇÕES FISCAIS (use seu conhecimento, busque o mais específico possível):
- ncm: Nomenclatura Comum do Mercosul — código de 8 dígitos com pontos (ex: 8541.40.16) para produtos físicos; string vazia para serviços puros
- unspsc_codigo_completo: UNSPSC (Universal Standard Products and Services Classification) — código completo de 8 dígitos sem separadores (ex: 26111702); escolha o código de nível Commodity mais específico disponível
- nbsc: NBS (Nomenclatura Brasileira de Serviços, Intangíveis e Outras Operações) — código completo com pontos (ex: 1.0301.01.10) para serviços; string vazia para produtos físicos

CLASSIFICAÇÃO CONTÁBIL (sugira baseado no tipo de bem/serviço, seguindo o Plano de Contas padrão NBC TG):
- conta_contabil: código e nome da conta contábil mais adequada. Use os padrões:
  * Equipamentos/bens de capital para uso próprio → "1.2.3.01 - Equipamentos"
  * Mercadorias/materiais para revenda → "1.1.3.01 - Estoques de Mercadorias"
  * Materiais de consumo → "1.1.3.02 - Materiais de Consumo"
  * Serviços de instalação/manutenção → "3.2.1.05 - Despesas com Serviços de Terceiros PJ"
  * Serviços de engenharia/projetos → "3.2.1.06 - Despesas com Serviços Técnicos PJ"
- natureza_contabil: natureza da conta. Use exatamente um dos valores:
  * "ATIVO CIRCULANTE" (estoques, materiais)
  * "ATIVO NÃO CIRCULANTE" (equipamentos, imobilizado)
  * "DESPESA OPERACIONAL" (serviços, manutenção)
  * "CUSTO" (custo de mercadoria vendida)

Retorne APENAS JSON válido, sem markdown, sem texto adicional:
{"itens": [{"codigo": "", "nome": "", "descricao_curta": "", "descricao_longa": "", "unidade": "", "categoria": "", "preco_unitario": 0, "fabricante": "", "ncm": "", "unspsc_codigo_completo": "", "nbsc": "", "conta_contabil": "", "natureza_contabil": ""}]}`
            }
        ]
    }]
});

return item;

const resp = $input.first().json;

let raw = '';
try {
    raw = resp.content[0].text;
} catch(e) {
    throw new Error('Resposta inesperada da Claude API: ' + JSON.stringify(resp).substring(0, 400));
}

raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
    parsed = JSON.parse(raw);
} catch(e) {
    throw new Error('Resposta não é JSON válido. Início: ' + raw.substring(0, 400));
}

const itens = parsed.itens || [];
if (!itens.length) {
    throw new Error('Nenhum item encontrado. Resposta: ' + raw.substring(0, 400));
}

const campos = $('04 — Montar Requisição Claude').first().json;
const hoje = new Date().toLocaleDateString('pt-BR');

return itens.map(i => ({
    json: {
        data_solicitacao:      hoje,
        solicitante:           String(campos.solicitante           || ''),
        email_solicitante:     String(campos.email_solicitante     || ''),
        status_aprovacao:      'PENDENTE',
        codigo:                String(i.codigo                || ''),
        nome:                  String(i.nome                  || ''),
        descricao_curta:       String(i.descricao_curta       || ''),
        descricao_longa:       String(i.descricao_longa       || ''),
        unidade:               String(i.unidade               || ''),
        categoria:             String(i.categoria             || ''),
        preco_unitario:        Number(i.preco_unitario)       || 0,
        fabricante:            String(i.fabricante            || ''),
        ncm:                   String(i.ncm                  || ''),
        unspsc_codigo_completo: String(i.unspsc_codigo_completo || ''),
        nbsc:                  String(i.nbsc                 || ''),
        conta_contabil:        String(i.conta_contabil        || ''),
        natureza_contabil:     String(i.natureza_contabil     || '')
    }
}));
